const r=()=>{const e=document.cookie.split(";").map(o=>o.trim()),t=e.find(o=>o.startsWith("XSRF-TOKEN="));if(t)return decodeURIComponent(t.split("=")[1]||"");const n=e.find(o=>o.startsWith("csrftoken="));return n?decodeURIComponent(n.split("=")[1]||""):document.querySelector('meta[name="csrf-token"]')?.getAttribute("content")||""},c=(e={})=>{const t=r();return t?{...e,"X-XSRF-TOKEN":t,"X-CSRFToken":t}:{...e}};export{c as g};
